int array_sum(int* arr, int n) {
    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += arr[i];
    }
    return sum;
}

struct Point {
    int x;
    int y;
};

int manhattan_distance(struct Point* p1, struct Point* p2) {
    int dx = p1->x - p2->x;
    int dy = p1->y - p2->y;
    if (dx < 0) dx = -dx;
    if (dy < 0) dy = -dy;
    return dx + dy;
}

void bubble_sort(int* arr, int n) {
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                int tmp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = tmp;
            }
        }
    }
}

struct Node {
    int value;
    struct Node* next;
};

int list_length(struct Node* head) {
    int count = 0;
    struct Node* current = head;
    while (current != 0) {
        count = count + 1;
        current = current->next;
    }
    return count;
}

